    let d1 = a.max_x - b.min_x;
    let d2 = b.max_y - a.min_y;
    let d3 = a.max_y - b.min_y;
    let d4 = b.max_z - a.min_z;
    let d5 = a.max_z - b.min_z;
    // Witness: extract sign bits (bit 63 of each i64 difference)
    let s0 = I64F64::from_num((d0 >> 63) & 1);
    let s1 = I64F64::from_num((d1 >> 63) & 1);
    let s2 = I64F64::from_num((d2 >> 63) & 1);
    let s3 = I64F64::from_num((d3 >> 63) & 1);
    let s4 = I64F64::from_num((d4 >> 63) & 1);
    let s5 = I64F64::from_num((d5 >> 63) & 1);
    // Ring: product of (1 - sᵢ) = 1 iff all non-negative
