fn pow_int(base: I64F64, exp: I64F64) -> I64F64 {
    let mut r = I64F64::ONE; let mut b = base; let mut e = exp.to_num::<i64>();
    while e > 0 { if e & 1 == 1 { r = r.wrapping_mul(b); } b = b.wrapping_mul(b); e >>= 1; } r
}

#[inline(always)]
pub fn predictive_cost(min_x: I64F64, max_x: I64F64, min_y: I64F64, max_y: I64F64, min_z: I64F64, max_z: I64F64, vx: I64F64, vy: I64F64, vz: I64F64, ax: I64F64, ay: I64F64, az: I64F64, ticks_ahead: I64F64) -> I64F64 {
    let t0: I64F64 = ((-I64F64::ONE) * min_x);
    let t1: I64F64 = (max_x + t0);
    let t2: I64F64 = (vx * ticks_ahead);
    let t3: I64F64 = (t1 + t2);
    let t4: I64F64 = (ticks_ahead * ticks_ahead);
    let t5: I64F64 = (ax * t4);
    let t6: I64F64 = (t3 + t5);
    let t7: I64F64 = ((-I64F64::ONE) * min_y);
    let t8: I64F64 = (max_y + t7);
    let t9: I64F64 = (vy * ticks_ahead);
    let t10: I64F64 = (t8 + t9);
    let t11: I64F64 = (ay * t4);
    let t12: I64F64 = (t10 + t11);
    let t13: I64F64 = (t6 * t12);
    let t14: I64F64 = ((-I64F64::ONE) * min_z);
    let t15: I64F64 = (max_z + t14);
    let t16: I64F64 = (vz * ticks_ahead);
    let t17: I64F64 = (t15 + t16);
    let t18: I64F64 = (az * t4);
    let t19: I64F64 = (t17 + t18);
    let t20: I64F64 = (t12 * t19);
    let t21: I64F64 = (t13 + t20);
    let t22: I64F64 = (t6 * t19);
    let t23: I64F64 = (t21 + t22);
    let t24: I64F64 = (I64F64::from_num(2i64) * t23);
    let t25: I64F64 = (t24 + I64F64::ONE);
    t25
}

#[inline(always)]
pub fn delta_cost_1(v: I64F64, a_half: I64F64) -> I64F64 {
    let t0: I64F64 = (v + a_half);
    t0
}

