/// Per-entity δ: largest candidate where v·δ + ah·δ² ≤ R.
/// Polynomial cost evaluation via E-graph; selection is non-ring postprocessing.
/// Source of truth: perEntityDelta (Sim.lean:407)
#[inline]
pub fn per_entity_delta_poly(v: I64F64, a_half: I64F64) -> u32 {
    if delta_cost_120(v, a_half) <= I64F64::from_num(5000000i64) { return 120; }
    if delta_cost_100(v, a_half) <= I64F64::from_num(5000000i64) { return 100; }
    if delta_cost_80(v, a_half) <= I64F64::from_num(5000000i64) { return 80; }
    if delta_cost_64(v, a_half) <= I64F64::from_num(5000000i64) { return 64; }
    if delta_cost_48(v, a_half) <= I64F64::from_num(5000000i64) { return 48; }
    if delta_cost_32(v, a_half) <= I64F64::from_num(5000000i64) { return 32; }
    if delta_cost_24(v, a_half) <= I64F64::from_num(5000000i64) { return 24; }
    if delta_cost_16(v, a_half) <= I64F64::from_num(5000000i64) { return 16; }
    if delta_cost_8(v, a_half) <= I64F64::from_num(5000000i64) { return 8; }
    if delta_cost_4(v, a_half) <= I64F64::from_num(5000000i64) { return 4; }
    if delta_cost_2(v, a_half) <= I64F64::from_num(5000000i64) { return 2; }
    if delta_cost_1(v, a_half) <= I64F64::from_num(5000000i64) { return 1; }
    1
}


/// Quintic Hermite spline basis functions (C³ continuity).
/// t = numer/denom ∈ [0,1] where numer=ticks_since_build, denom=delta.
/// Return values are integer numerators in μm units:
///   h00, h01, h10, h11 : divide result by denom^5
///   h20, h21            : divide result by 2·denom^5
/// Interpolated position (μm):
///   pos = (h00*p0 + h01*p1 + h10*v0*T + h11*v1*T + h20*a0*T² + h21*a1*T²) / denom^5
/// where T = delta (ticks), p in μm, v in μm/tick, a in μm/tick².
/// Source of truth: PredictiveBVH.QuinticHermite (C³ proofs in Lean).
/// h00(t) numerator (÷ denom^5): position weight at t=0
#[inline(always)]
pub fn bvh_h00(numer: I64F64, denom: I64F64) -> I64F64 {
    let t0: I64F64 = pow_int(denom, I64F64::from_num(5i64));
    let t1: I64F64 = pow_int(numer, I64F64::from_num(3i64));
    let t2: I64F64 = (I64F64::from_num(10i64) * t1);
    let t3: I64F64 = (denom * denom);
    let t4: I64F64 = (t2 * t3);
    let t5: I64F64 = ((-I64F64::ONE) * t4);
    let t6: I64F64 = (t0 + t5);
    let t7: I64F64 = pow_int(numer, I64F64::from_num(4i64));
    let t8: I64F64 = (I64F64::from_num(15i64) * t7);
    let t9: I64F64 = (t8 * denom);
    let t10: I64F64 = (t6 + t9);
    let t11: I64F64 = pow_int(numer, I64F64::from_num(5i64));
    let t12: I64F64 = (I64F64::from_num(6i64) * t11);
    let t13: I64F64 = ((-I64F64::ONE) * t12);
    let t14: I64F64 = (t10 + t13);
    t14
}

/// h01(t) numerator (÷ denom^5): position weight at t=1
#[inline(always)]
pub fn bvh_h01(numer: I64F64, denom: I64F64) -> I64F64 {
    let t0: I64F64 = pow_int(numer, I64F64::from_num(3i64));
    let t1: I64F64 = (I64F64::from_num(10i64) * t0);
    let t2: I64F64 = (denom * denom);
    let t3: I64F64 = (t1 * t2);
    let t4: I64F64 = pow_int(numer, I64F64::from_num(4i64));
    let t5: I64F64 = (I64F64::from_num(15i64) * t4);
    let t6: I64F64 = (t5 * denom);
    let t7: I64F64 = ((-I64F64::ONE) * t6);
    let t8: I64F64 = (t3 + t7);
    let t9: I64F64 = pow_int(numer, I64F64::from_num(5i64));
    let t10: I64F64 = (I64F64::from_num(6i64) * t9);
    let t11: I64F64 = (t8 + t10);
    t11
}

/// h10(t) numerator (÷ denom^5): velocity×T weight at t=0
#[inline(always)]
pub fn bvh_h10(numer: I64F64, denom: I64F64) -> I64F64 {
    let t0: I64F64 = pow_int(denom, I64F64::from_num(4i64));
    let t1: I64F64 = (numer * t0);
    let t2: I64F64 = pow_int(numer, I64F64::from_num(3i64));
    let t3: I64F64 = (I64F64::from_num(6i64) * t2);
    let t4: I64F64 = (denom * denom);
    let t5: I64F64 = (t3 * t4);
    let t6: I64F64 = ((-I64F64::ONE) * t5);
    let t7: I64F64 = (t1 + t6);
    let t8: I64F64 = pow_int(numer, I64F64::from_num(4i64));
    let t9: I64F64 = (I64F64::from_num(8i64) * t8);
    let t10: I64F64 = (t9 * denom);
    let t11: I64F64 = (t7 + t10);
    let t12: I64F64 = pow_int(numer, I64F64::from_num(5i64));
    let t13: I64F64 = (I64F64::from_num(3i64) * t12);
    let t14: I64F64 = ((-I64F64::ONE) * t13);
    let t15: I64F64 = (t11 + t14);
    t15
}

/// h11(t) numerator (÷ denom^5): velocity×T weight at t=1
#[inline(always)]
pub fn bvh_h11(numer: I64F64, denom: I64F64) -> I64F64 {
    let t0: I64F64 = pow_int(numer, I64F64::from_num(3i64));
    let t1: I64F64 = ((-I64F64::from_num(4i64)) * t0);
    let t2: I64F64 = (denom * denom);
    let t3: I64F64 = (t1 * t2);
    let t4: I64F64 = pow_int(numer, I64F64::from_num(4i64));
    let t5: I64F64 = (I64F64::from_num(7i64) * t4);
    let t6: I64F64 = (t5 * denom);
    let t7: I64F64 = (t3 + t6);
    let t8: I64F64 = pow_int(numer, I64F64::from_num(5i64));
    let t9: I64F64 = (I64F64::from_num(3i64) * t8);
    let t10: I64F64 = ((-I64F64::ONE) * t9);
    let t11: I64F64 = (t7 + t10);
    t11
}

/// h20(t) numerator (÷ 2·denom^5): accel×T² weight at t=0
#[inline(always)]
pub fn bvh_h20(numer: I64F64, denom: I64F64) -> I64F64 {
    let t0: I64F64 = (numer * numer);
    let t1: I64F64 = pow_int(denom, I64F64::from_num(3i64));
    let t2: I64F64 = (t0 * t1);
    let t3: I64F64 = pow_int(numer, I64F64::from_num(3i64));
    let t4: I64F64 = (I64F64::from_num(3i64) * t3);
    let t5: I64F64 = (denom * denom);
    let t6: I64F64 = (t4 * t5);
    let t7: I64F64 = ((-I64F64::ONE) * t6);
    let t8: I64F64 = (t2 + t7);
    let t9: I64F64 = pow_int(numer, I64F64::from_num(4i64));
    let t10: I64F64 = (I64F64::from_num(3i64) * t9);
    let t11: I64F64 = (t10 * denom);
    let t12: I64F64 = (t8 + t11);
    let t13: I64F64 = pow_int(numer, I64F64::from_num(5i64));
    let t14: I64F64 = ((-I64F64::ONE) * t13);
    let t15: I64F64 = (t12 + t14);
    t15
}

/// h21(t) numerator (÷ 2·denom^5): accel×T² weight at t=1
#[inline(always)]
pub fn bvh_h21(numer: I64F64, denom: I64F64) -> I64F64 {
    let t0: I64F64 = pow_int(numer, I64F64::from_num(3i64));
    let t1: I64F64 = (denom * denom);
    let t2: I64F64 = (t0 * t1);
    let t3: I64F64 = pow_int(numer, I64F64::from_num(4i64));
    let t4: I64F64 = (I64F64::from_num(2i64) * t3);
    let t5: I64F64 = (t4 * denom);
    let t6: I64F64 = ((-I64F64::ONE) * t5);
    let t7: I64F64 = (t2 + t6);
    let t8: I64F64 = pow_int(numer, I64F64::from_num(5i64));
    let t9: I64F64 = (t7 + t8);
    t9
}

#[inline(always)]
pub fn bvh_blend(flag: I64F64, old_val: I64F64, new_val: I64F64) -> I64F64 {
    let t0: I64F64 = ((-I64F64::ONE) * old_val);
    let t1: I64F64 = (new_val + t0);
    let t2: I64F64 = (flag * t1);
    let t3: I64F64 = (old_val + t2);
    t3
}